/**
 * The full per-site performance configuration. `cdn_credentials` is
 * write-only (see CdnCredentials); `cdn_has_credentials` and the
 * install-state fields (`server_software`, `dropin_installed`,
 * `wp_cache_constant_set`, `htaccess_managed`) are read-only / server- or
 * agent-derived.
 *
 */
export type PerfConfigWritable = {
  cache_enabled?: boolean;
  cache_logged_in?: boolean;
  cache_mobile?: boolean;
  cache_refresh?: boolean;
  cache_refresh_interval?: string;
  cache_link_prefetch?: boolean;
  cache_bypass_urls?: Array<string>;
  cache_bypass_cookies?: Array<string>;
  cache_include_queries?: Array<string>;
  cache_include_cookies?: Array<string>;
  preload_concurrency?: number;
  preload_delay_ms?: number;
  preload_batch_size?: number;
  preload_max_load?: number;
  css_js_minify?: boolean;
  css_rucss?: boolean;
  css_rucss_include_selectors?: Array<string>;
  css_js_self_host_third_party?: boolean;
  js_delay?: boolean;
  js_delay_method?: string;
  js_delay_excludes?: Array<string>;
  js_delay_third_party?: boolean;
  js_delay_third_party_excludes?: Array<string>;
  fonts_display_swap?: boolean;
  fonts_optimize_google?: boolean;
  fonts_preload?: boolean;
  /**
   * Enable server-side TTF/OTF/WOFF → WOFF2 transcoding for self-hosted fonts. When true the agent requests transcode jobs from the CP; the CP enqueues a font_transcode River job which produces the WOFF2 in object storage. Default false.
   *
   */
  fonts_transcode_woff2?: boolean;
  /**
   * Enable subset-WOFF2 production (Phase 2, experimental). When true the media-encoder also produces a subset WOFF2 restricted to the unicode range specified by fonts_subset_range. Default false (opt-in).
   *
   */
  fonts_subset?: boolean;
  /**
   * Subsetting strategy. "range" (fixed unicode-range block) is the only supported mode in v1. Stored for forward compatibility.
   *
   */
  fonts_subset_mode?: string;
  /**
   * Named unicode range to subset to. "latin-ext" is the safe default (U+0000-024F, U+1E00-1EFF).
   *
   */
  fonts_subset_range?: string;
  lazy_load?: boolean;
  lazy_load_exclusions?: Array<string>;
  properly_size_images?: boolean;
  youtube_placeholder?: boolean;
  self_host_gravatars?: boolean;
  cdn_enabled?: boolean;
  cdn_url?: string;
  cdn_file_types?: string;
  cdn_provider?: string;
  cdn_credentials?: CdnCredentials;
  db_auto_clean?: boolean;
  db_auto_clean_interval?: string;
  db_post_revisions?: boolean;
  db_post_auto_drafts?: boolean;
  db_post_trashed?: boolean;
  db_comments_spam?: boolean;
  db_comments_trashed?: boolean;
  db_transients_expired?: boolean;
  db_optimize_tables?: boolean;
  bloat_disable_block_css?: boolean;
  bloat_disable_dashicons?: boolean;
  bloat_disable_emojis?: boolean;
  bloat_disable_jquery_migrate?: boolean;
  bloat_disable_xml_rpc?: boolean;
  bloat_disable_rss_feed?: boolean;
  bloat_disable_oembeds?: boolean;
  bloat_heartbeat_control?: boolean;
  bloat_post_revisions_control?: boolean;
  /**
   * When true the agent will cache the WooCommerce catalog shell for
   * anonymous shoppers who have an active cart. The agent additionally
   * hard-gates on its own theme probe (`woo_theme_fragments_supported`)
   * before serving cached pages to cart-holding visitors, providing a
   * defense-in-depth layer independent of this flag.
   * The API accepts `woo_cacheable_session: true` even when
   * `woo_theme_fragments_supported` is false — the agent will not act on
   * it until its own probe passes. This allows operators to pre-enable the
   * flag before the agent performs its first probe.
   *
   */
  woo_cacheable_session?: boolean;
};

